#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <limits>

// This driver illustrates how to set up I/O redirection to test
// a C++ program that prompts for input and prints to console.
// It assumes the user's solution is compiled into an executable
// (e.g., 'solution.exe') and this driver would then execute it
// with redirected standard input and capture standard output.

// For demonstration purposes within this C++ snippet,
// let's assume the core logic of the user's program
// is encapsulated in a function called `user_program_main_logic()`.
// In a real testing environment, `user_program_main_logic()` would
// represent the execution of the user's compiled `main` function.

// A placeholder for the user's program logic,
// which would normally be the content of their `main` function.
// This function is purely illustrative for the driver's explanation.
// It is NOT the user's actual code, but represents what the driver
// would be running.
int user_program_main_logic() {
    std::string inputString;
    char searchChar;

    std::cout << "Enter a string: ";
    std::getline(std::cin, inputString);

    std::cout << "Enter a character to count: ";
    std::cin >> searchChar;

    std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n'); // To clear potential remaining newline

    int count = 0;
    for (char c : inputString) {
        if (c == searchChar) {
            count++;
        }
    }
    std::cout << "The character '" << searchChar << "' appears " << count << " times in \"" << inputString << "\"." << std::endl;
    return 0;
}


int main() {
    // Example of how one test case would be executed:
    std::string input_for_test = "example string\ne\n"; // Simulate user input
    std::stringstream ss_input(input_for_test);
    std::stringstream ss_output;

    // Save original cin/cout buffers
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();

    // Redirect cin and cout to stringstreams
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    // Execute the user's program logic
    // In a real test, this might involve forking a process and executing
    // the compiled user's solution, redirecting its stdin/stdout.
    // For this C++ driver snippet, we call an illustrative function.
    user_program_main_logic();

    // Restore original cin/cout buffers
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    // The captured output is now in ss_output.str()
    // This output would then be compared against the expected output
    // defined in the test case.
    // std::cout << "Captured output:\n" << ss_output.str() << std::endl;

    return 0;
}
